/*
 * Option 4 benchmark — ONNX -> importNetworkFromONNX -> dlnetwork -> MATLAB Coder (R2026a)
 * C code generated by MATLAB Coder 26.1, Embedded Coder, DeepLearningConfig=none.
 */
#include <stdio.h>
#include <time.h>
#include "codegen_opt4/lstm_infer_opt4.h"
#include "codegen_opt4/lstm_infer_opt4_initialize.h"
#include "codegen_opt4/lstm_infer_opt4_terminate.h"
#include "../benchmark/shared_test_input.h"

#define N_WARMUP  50
#define N_RUNS   1000

int main(void)
{
    int predictions[75];
    int i, t;
    clock_t t0, t1;
    double total_ms, per_run_ms;

    lstm_infer_opt4_initialize();

    for (i = 0; i < N_WARMUP; i++)
        lstm_infer_opt4((const float *)shared_test_input, predictions);

    t0 = clock();
    for (i = 0; i < N_RUNS; i++)
        lstm_infer_opt4((const float *)shared_test_input, predictions);
    t1 = clock();

    total_ms   = (double)(t1 - t0) / CLOCKS_PER_SEC * 1000.0;
    per_run_ms = total_ms / N_RUNS;

    printf("Option 4: MATLAB Coder (ONNX->importNetworkFromONNX->dlnetwork, R2026a)\n");
    printf("  Runs/warmup : %d / %d\n", N_RUNS, N_WARMUP);
    printf("  Total time  : %.4f ms\n", total_ms);
    printf("  Per run     : %.4f ms  (%.2f us)\n", per_run_ms, per_run_ms * 1000.0);
    printf("  Predictions [%d steps]: [", SHARED_SEQ_LEN);
    for (t = 0; t < SHARED_SEQ_LEN; t++)
        printf("%d%s", predictions[t], t < SHARED_SEQ_LEN - 1 ? " " : "]\n");

    lstm_infer_opt4_terminate();
    return 0;
}
